// Function to compute the Fibonacci sequence
std::vector<int> fibonacci_sequence(int n, int shift) {
    std::vector<int> series(n);

    // Base cases
    series[0] = shift;
    if (n > 1) {
        series[1] = 1 + shift;
    }

    // Fibonacci sequence calculation
    for (int i = 2; i < n; i++) {
        series[i] = series[i - 1] + series[i - 2];
    }

    return series;
}

