    int sum = 0;
    for (int i = 0; i < fibonacci.size(); i++) {
        sum += fibonacci[i];
    }

    // Output the Fibonacci sequence
    std::cout << "Fibonacci sequence with shift " << shift << ": ";
    for (int i = 0; i < fibonacci.size(); i++) {
        std::cout << fibonacci[i] << " ";
