content = "#include <occi.h>       
#include <iostream>
#include <cstring>

using namespace std;
using namespace oracle::occi;

int main() {
    Environment *env = Environment::createEnvironment("AL32UTF8", "AL32UTF8", Environment::DEFAULT);
    try {
        // OCCI does not directly support wallet-based connections via CreateConnection.
        // The workaround is using the underlying OCI functionality.

        OCIEnv *oci_env = env->getOCIEnvironment();
        OCIError *errhp;
        OCIServer *srvhp;
        OCISvcCtx *svchp;
        OCISession *usrhp;

        // Allocate handles
        OCIHandleAlloc((dvoid *) oci_env, (dvoid **) &errhp, OCI_HTYPE_ERROR, 0, 0);
        OCIHandleAlloc((dvoid *) oci_env, (dvoid **) &srvhp, OCI_HTYPE_SERVER, 0, 0);
        OCIHandleAlloc((dvoid *) oci_env, (dvoid **) &svchp, OCI_HTYPE_SVCCTX, 0, 0);
        OCIHandleAlloc((dvoid *) oci_env, (dvoid **) &usrhp, OCI_HTYPE_SESSION, 0, 0);

        // Server Attach with the TNS Entry (TestDB)
        OCIServerAttach(srvhp, errhp, (OraText *) "TestDB", strlen("TestDB"), 0);

        // Set Service Context server attribute
        OCIAttrSet((dvoid *)svchp, OCI_HTYPE_SVCCTX, (dvoid *)srvhp, 0, OCI_ATTR_SERVER, errhp);

        // To use wallet, we typically use OCI_SYSAuthenticated or omit user/pass 
        // depending on the wallet configuration (External Authentication).
        // This part requires specific OCI session setup for wallet-based auth.

        std::cout << "OCI handles initialized and server attached to TestDB using wallet configuration." << std::endl;

        // Clean up
        OCIServerDetach(srvhp, errhp);
        OCIHandleFree(srvhp, OCI_HTYPE_SERVER);
        OCIHandleFree(errhp, OCI_HTYPE_ERROR);
        OCIHandleFree(svchp, OCI_HTYPE_SVCCTX);
        OCIHandleFree(usrhp, OCI_HTYPE_SESSION);

