content = "import numpy as np
import time

# initialize the Q-matrix
FIB_MATRIX = np.array([[1, 1], [1, 0]], dtype=object)

# LRU Cache to store previously calculated powers of the matrix
cache = {}

def matrix_power(matrix, n):
    if n == 0:
        return np.eye(2, dtype=object)
    elif n == 1:
        return matrix

    if n in cache:
        return cache[n]

    sub_power = matrix_power(matrix, n // 2)
    result = np.dot(sub_power, sub_power)

    if n % 2 != 0:
        result = np.dot(matrix, result)

    cache[n] = result
    return result

def fibonacci_series(n):
    try:
        n = int(n)
        if n < 0:
            raise ValueError
    except (ValueError, TypeError):
        raise ValueError('Input must be a non-negative integer')

    if n == 0:
        return []
    if n == 1:
        return [0]

    series = [0, 1]
    # To get the series up to n terms, we can iterate or use the matrix property
    # The matrix M^k gives the (k+1)-th Fibonacci number at [0,0]
    for i in range(2, n):
        res = matrix_power(FIB_MATRIX, i)
        series.append(int(res[0, 0]))

    return series

def benchmark_fibonacci(terms_list):
    results = {}
    for terms in terms_list:
        start_time = time.time()
        try:
            fibonacci_series(terms)
            end_time = time.time()
            results[terms] = end_time - start_time
        except Exception as e:
            results[terms] = str(e)
    return results

if __name__ == '__main__':
    try:
        print('Fibonacci(10):', fibonacci_series(10))
        print('Benchmark:', benchmark_fibonacci([10, 100, 1000, -1, 'abc']))
    except Exception as e:
        print(e)
"
