// 'x' is rounded and its absolute value is taken because Fibonacci sequence is usually defined for non-negative integers.
func fibonacciSequence(x float64) int {
	pos := int(math.Round(math.Abs(x))) // convert 'x' to an absolute rounded int

	if pos == 0 {
		return 0 // if 'pos' is 0, return 0
	} else {
		// create a slice to hold the fibonacci sequence
		fib := make([]int, pos+1)
		// initialize the first two numbers of the sequence
		fib[0], fib[1] = 0, 1

		// calculate the rest of the sequence
		for i := 2; i <= pos; i++ {
			fib[i] = fib[i-1] + fib[i-2]
		}

		return fib[pos] // return the number at the 'pos' position in the sequence
	}
}

func main() {
	fmt.Println(fibonacciSequence(9.1))  // prints: 34
	fmt.Println(fibonacciSequence(20.9)) // prints: 6765
	fmt.Println(fibonacciSequence(-9.1)) // prints: 34
