content = "import numpy as np

def fibonacci(num):
    if num == 0: return 0
    if num == 1: return 1

    fibonacci_matrix = np.matrix([[1, 1], [1, 0]], dtype='int64')

    def matrix_power(mat, p):
        if p == 0:
            return np.identity(2, dtype='int64')
        elif p == 1:
            return mat
        else:
            half_p = matrix_power(mat, p // 2)
            if p % 2 == 0:
                return half_p * half_p
            else:
                return mat * half_p * half_p

    res_mat = matrix_power(fibonacci_matrix, num)
    # Use item() as asscalar is deprecated in newer numpy versions
    return int(res_mat[1, 0])

