content = "from typing import List, Union
from functools import lru_cache

@lru_cache(maxsize=None)
def fibonacci(i: int) -> int:
    if i < 0:
        raise ValueError("Invalid Fibonacci number")
    elif i <= 1:
        return i
    else:
        return fibonacci(i-1) + fibonacci(i-2)

def get_fib_range_recursive(n: int, m: int, i: int = 0, current_list: List[int] = None) -> Union[List[int], str]:
    if current_list is None:
        current_list = []

    val = fibonacci(i)
    if val > m:
        # Check if the last element is exactly m, otherwise m wasn't in the sequence
        if not current_list or current_list[-1] != m:
            return "Given values are not in the Fibonacci series"
        # Also check if n was ever found
        if not current_list or current_list[0] != n:
            return "Given values are not in the Fibonacci series"
        return current_list

    if val >= n:
        current_list.append(val)

    return get_fib_range_recursive(n, m, i + 1, current_list)

# Wrapper to handle the specific 'n' and 'm' existence check
def fibonacci_range(n: int, m: int) -> Union[List[int], str]:
    # First, verify if n and m are actually Fibonacci numbers
    # Since we can't use loops, we use a recursive check
    def is_fib(target, i=0):
        f = fibonacci(i)
        if f == target: return True
        if f > target: return False
        return is_fib(target, i + 1)

    if not is_fib(n) or not is_fib(m):
        return "Given values are not in the Fibonacci series"

    return get_fib_range_recursive(n, m)
"
