content = "class Node:
    def __init__(self, data):
        self.data = data
        self.height = 0
        self.left = None
        self.right = None

class AVL:
    def __init__(self):
        self.root = None

    def calc_height(self, node):
        if not node:
            return -1
        return node.height

    def calc_balance(self, node):
        return self.calc_height(node.left) - self.calc_height(node.right)

    def rotate_right(self, node):
        new_root = node.left
        node.left = new_root.right
        new_root.right = node
        node.height = max(self.calc_height(node.left), self.calc_height(node.right)) + 1
        new_root.height = max(self.calc_height(new_root.left), self.calc_height(new_root.right)) + 1
        return new_root

    def rotate_left(self, node):
        new_root = node.right
        node.right = new_root.left
        new_root.left = node
        node.height = max(self.calc_height(node.left), self.calc_height(node.right)) + 1
        new_root.height = max(self.calc_height(new_root.left), self.calc_height(new_root.right)) + 1
        return new_root

    def re_balance(self, node):
        balance = self.calc_balance(node)
        if balance > 1:
            if self.calc_balance(node.left) < 0:
                node.left = self.rotate_left(node.left)
            return self.rotate_right(node)
        if balance < -1:
            if self.calc_balance(node.right) > 0:
                node.right = self.rotate_right(node.right)
            return self.rotate_left(node)
        return node

    def insert(self, node, data):
        if not node:
            return Node(data)
        if data < node.data:
            node.left = self.insert(node.left, data)
        else:
            node.right = self.insert(node.right, data)
        node.height = max(self.calc_height(node.left), self.calc_height(node.right)) + 1
        return self.re_balance(node)

    def add(self, data):
        self.root = self.insert(self.root, data)

    def get_inorder(self, node, res):
        if node:
            self.get_inorder(node.left, res)
            res.append(node.data)
            self.get_inorder(node.right, res)

def synthesize_fibonacci_tree(n):
    tree = AVL()
    a, b = 0, 1
    while a <= n:
        tree.add(a)
        a, b = b, a + b
    return tree

