/**
 * Finds the longest oscillating subsequence of a string consisting of '0's and '1's.
 * An oscillating sequence alternates between '1' and '0'.
 */
char *longest_oscillating_subseq(char *s) {
    int n = strlen(s);
    if (n == 0) return strdup("");

    char val[2] = {'1', '0'};
    int *dp = (int*) malloc(n * sizeof(int));
    int *pos = (int*) malloc(n * sizeof(int));

    for(int i = 0; i < n; i++) {
        dp[i] = 1;
        pos[i] = -1;
    }

    int best_end = 0;

    for(int i = 1; i < n; i++) {
        for(int j = 0; j < i; j++) {
            // Characters must be different to oscillate
            if(s[i] == s[j])
                continue;
            // Check if current char matches the required alternating value based on length
            else if(dp[j] + 1 > dp[i] && s[i] == val[dp[j] % 2]) {
                dp[i] = dp[j] + 1;
                pos[i] = j;
            }
        }
        if(dp[i] > dp[best_end])
            best_end = i;
    }

    // Reconstruct the string from the best end position
    char *osci_subseq = (char*) malloc((dp[best_end] + 1) * sizeof(char));
    int k = dp[best_end];
    osci_subseq[k] = '\0';
    k--;
    int i = best_end;
    while(i != -1) {
        osci_subseq[k] = s[i];
        k--;
        i = pos[i];
    }

    free(dp);
    free(pos);
    return osci_subseq;
}

/**
 * Computes the XOR of two binary strings and then finds the longest oscillating subsequence of the result.
 */
char *string_xor_alternating_subseq(char *a, char *b) {
    int len = strlen(a);

    char *xor_result = (char*) malloc((len + 1) * sizeof(char));
    xor_result[len] = '\0';

    for(int i = 0; i < len; i++) {
        // XOR the characters by converting '0'/'1' to integers
        xor_result[i] = ((a[i] - '0') ^ (b[i] - '0')) + '0';
    }

    char *longest_oscillating_sequence = longest_oscillating_subseq(xor_result);
    free(xor_result);

    return longest_oscillating_sequence;
}

int main() {
    char a[] = "1100";
    char b[] = "1010";
    char *res = string_xor_alternating_subseq(a, b);
